20	// Test seams: tests assert that ResolveProfileLadder and ResolveTierModelRef
21	// are NOT in the call graph on the default routing path (ddx-755f5881 AC #3).
22	// Production code never reads these counters; they are exported only for tests.
23	var (
24		resolveProfileLadderCalls atomic.Int64
25		resolveTierModelRefCalls  atomic.Int64
26	)
27	
28	// ResolveProfileLadderCallCount returns the current value of the call counter.
29	// Tests use it together with ResetRoutingCallCounters to verify call-graph claims.
30	func ResolveProfileLadderCallCount() int64 { return resolveProfileLadderCalls.Load() }
31	
32	// ResolveTierModelRefCallCount returns the current value of the call counter.
33	func ResolveTierModelRefCallCount() int64 { return resolveTierModelRefCalls.Load() }
34	
35	// ResetRoutingCallCounters zeros the test-seam counters.
36	func ResetRoutingCallCounters() {
37		resolveProfileLadderCalls.Store(0)
38		resolveTierModelRefCalls.Store(0)
39	}
40	
41	// ResolveProfileLadder returns the ordered tiers to try for profile after
42	// applying explicit --min-tier / --max-tier caps.
43	func ResolveProfileLadder(routing *config.RoutingConfig, profile, minTier, maxTier string) []escalation.ModelTier {
44		resolveProfileLadderCalls.Add(1)
45		profile = NormalizeRoutingProfile(profile)
46		ladder := routing.ResolvedLadder(profile)
47		out := make([]escalation.ModelTier, 0, len(ladder))
48		for _, raw := range ladder {
49			tier := strings.TrimSpace(raw)
50			if tier == "" || !tierWithinBounds(tier, minTier, maxTier) {
51				continue
52			}
53			out = append(out, escalation.ModelTier(tier))
54		}
55		return out
56	}
57	
58	func NormalizeRoutingProfile(profile string) string {
59		profile = strings.TrimSpace(profile)
60		if profile == "" {
61			return DefaultRoutingProfile
62		}
63		return profile
64	}
65	
66	// ResolveTierModelRef applies agent.routing.model_overrides for a ladder tier.
67	func ResolveTierModelRef(routing *config.RoutingConfig, tier escalation.ModelTier) string {
68		resolveTierModelRefCalls.Add(1)
69		tierRef := string(tier)
70		if routing != nil && routing.ModelOverrides != nil {
71			if override := strings.TrimSpace(routing.ModelOverrides[tierRef]); override != "" {
72				return override
73			}
74		}
75		return tierRef
76	}
77	
78	func tierWithinBounds(tier, minTier, maxTier string) bool {
79		rank, ok := profileTierRank[tier]
80		if !ok {
81			return minTier == "" && maxTier == ""
82		}
83		if minTier != "" {
84			if minRank, ok := profileTierRank[minTier]; ok && rank < minRank {
85				return false
86			}
87		}
88		if maxTier != "" {
89			if maxRank, ok := profileTierRank[maxTier]; ok && rank > maxRank {
90				return false
91			}
92		}
93		return true
94	}
