12	// ModelCatalogYAML is the on-disk format for the model catalog.
13	// Stored at ~/.ddx/model-catalog.yaml.
14	// Drives tier→model assignments and pricing without requiring a rebuild.
15	type ModelCatalogYAML struct {
16		Version   int                    `yaml:"version"`
17		UpdatedAt time.Time              `yaml:"updated_at"`
18		Tiers     map[string]TierDefYAML `yaml:"tiers"`  // tier name → surface→model
19		Models    []ModelEntryYAML       `yaml:"models"` // per-model metadata and pricing
20	}
21	
22	// TierDefYAML maps surfaces to concrete model strings for a tier.
23	type TierDefYAML struct {
24		Description string            `yaml:"description"`
25		Surfaces    map[string]string `yaml:"surfaces"` // surface → concrete model
26	}
27	
28	// ModelEntryYAML holds metadata for one model.
29	type ModelEntryYAML struct {
30		ID       string `yaml:"id"` // e.g. "claude-sonnet-4-6"
31		Provider string `yaml:"provider"`
32		Tier     string `yaml:"tier"`              // smart, standard, cheap
33		Blocked  bool   `yaml:"blocked,omitempty"` // if true, routing never selects this model
34		Notes    string `yaml:"notes,omitempty"`
35	}
36	
37	// DefaultModelCatalogPath returns the default path for the model catalog YAML.
38	func DefaultModelCatalogPath() string {
39		home, err := os.UserHomeDir()
40		if err != nil || home == "" {
41			return ""
42		}
43		return filepath.Join(home, ".ddx", "model-catalog.yaml")
44	}
45	
46	// LoadModelCatalogYAML loads the model catalog from the given path.
47	// Returns nil (no error) if the file does not exist — callers fall back to built-in defaults.
48	func LoadModelCatalogYAML(path string) (*ModelCatalogYAML, error) {
49		data, err := os.ReadFile(path)
50		if os.IsNotExist(err) {
51			return nil, nil
52		}
53		if err != nil {
54			return nil, err
55		}
56		var cat ModelCatalogYAML
57		if err := yaml.Unmarshal(data, &cat); err != nil {
58			return nil, fmt.Errorf("parse model catalog: %w", err)
59		}
60		return &cat, nil
61	}
62	
63	// WriteModelCatalogYAML writes the catalog to the given path, creating parent dirs.
64	func WriteModelCatalogYAML(path string, cat *ModelCatalogYAML) error {
65		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
66			return err
67		}
68		data, err := yaml.Marshal(cat)
69		if err != nil {
70			return err
71		}
72		return os.WriteFile(path, data, 0o644)
73	}
74	
75	// ApplyModelCatalogYAML overlays the YAML catalog onto a Catalog, adding or
76	// replacing entries for each tier defined in the YAML.
77	func ApplyModelCatalogYAML(cat *Catalog, yml *ModelCatalogYAML) {
78		if yml == nil || cat == nil {
79			return
80		}
81		for tierName, tierDef := range yml.Tiers {
82			entry := CatalogEntry{
83				Ref:      tierName,
84				Surfaces: make(map[string]string, len(tierDef.Surfaces)),
85			}
86			for surface, model := range tierDef.Surfaces {
87				entry.Surfaces[surface] = model
88			}
89			cat.AddOrReplace(entry)
90		}
91		for _, m := range yml.Models {
92			if m.Blocked {
93				cat.AddBlockedModelID(m.ID)
94			}
95		}
96	}
97	
